import { WorksheetData, ActivityType, StyleSettings } from '../types';

// Sayfa başına maksimum öğe sayısı (Aktivite tipine göre)
// Bu limitler, A4 kağıdının taşmaması için güvenli sınırlardır.
const ITEMS_PER_PAGE_CONFIG: Record<string, number> = {
    // Matematik
    'BASIC_OPERATIONS': 20,
    'MATH_PUZZLE': 6,
    'NUMBER_PATTERN': 10,
    'FUTOSHIKI': 4,
    'SUDOKU': 4,
    'PYRAMID': 4,

    // Sözel
    'WORD_SEARCH': 1, // Zaten tam sayfa
    'CROSSWORD': 1,
    'STORY_COMPREHENSION': 1,

    // Görsel / Dikkat
    'VISUAL_MEMORY': 6,
    'FIND_THE_DIFFERENCE': 3,
    'SHAPE_MATCHING': 4,
    'DOT_PAINTING': 1,

    // Varsayılan (Liste tabanlılar için)
    'DEFAULT': 8
};

// Verinin içindeki ana listeyi bulur (örn: sorular, itemler)
const findSplittableKeys = (dataItem: any): string[] => {
    const keys: string[] = [];

    // 1. Öncelik: Sections (Universal Schema)
    if (dataItem.sections && Array.isArray(dataItem.sections)) {
        return ['sections'];
    }

    // 2. Öncelik: Standart Listeler
    const priorityKeys = ['questions', 'puzzles', 'items', 'rows', 'patterns', 'operations', 'problems', 'groups', 'cards', 'drills'];
    for (const key of priorityKeys) {
        if (Array.isArray(dataItem[key]) && dataItem[key].length > 0) {
            keys.push(key);
        }
    }

    return keys;
};

export const paginationService = {
    process: (data: WorksheetData, activityType: ActivityType, settings?: StyleSettings): WorksheetData => {
        if (!data || data.length === 0) return [];

        // Rapor ve Kitapçık türlerini olduğu gibi bırak (Manuel sayfalama varsayılır)
        if (activityType === 'WORKBOOK' || activityType === 'ASSESSMENT_REPORT') return data;

        const newPages: any[] = [];
        const limit = ITEMS_PER_PAGE_CONFIG[activityType] || ITEMS_PER_PAGE_CONFIG['DEFAULT'];

        // Tüm gelen verileri (önceden sayfalara ayrılmış olsa bile) tek bir havuzda birleştirme mantığı
        // Ancak genellikle jeneratörler "worksheetCount" kadar *bağımsız* varyasyon üretir.
        // Eğer kullanıcı "100 soru, 5 sayfa" istediyse, jeneratör 5 tane 20'lik mi üretti yoksa 1 tane 100'lük mü?
        // Çoğu jeneratörümüz şu an bağımsız sayfalar (WorkshetCount döngüsü) üretiyor.
        // Bu yüzden her bir orijinal sayfayı kendi içinde sayfalamalıyız (taşma varsa).

        data.forEach((originalPage, pageIndex) => {
            const splitKeys = findSplittableKeys(originalPage);

            // Eğer bölünecek bir yapı yoksa olduğu gibi ekle
            if (splitKeys.length === 0) {
                newPages.push(originalPage);
                return;
            }

            // --- STRATEJİ 1: SECTIONS (YENİ TİP AKTİVİTELER) ---
            if (splitKeys.includes('sections')) {
                const sections = originalPage.sections;
                let currentPageSections: any[] = [];
                let currentHeight = 0; // Sanal yükseklik (item sayısı bazlı)

                sections.forEach((section: any) => {
                    const content = section.content || [];

                    // Bölüm başlığı ve yapısı da yer kaplar, onu da hesaba katalım (örn: 2 birim)
                    const headerCost = 2; 

                    // Eğer bölüm çok küçükse veya sığıyorsa direkt ekle
                    if (currentHeight + content.length + headerCost <= limit + 2) { // +2 esneklik
                        currentPageSections.push(section);
                        currentHeight += content.length + headerCost;
                    } else {
                        // SIĞMIYOR -> Bölümü Parçala (Splitting Logic)
                        let processedCount = 0;

                        while(processedCount < content.length) {
                            // Mevcut sayfada kalan yer
                            const remainingSpace = Math.max(1, limit - currentHeight - headerCost);

                            // Alabileceğim parça
                            const chunk = content.slice(processedCount, processedCount + remainingSpace);

                            if (chunk.length > 0) {
                                // Parçayı mevcut sayfaya ekle
                                currentPageSections.push({
                                    ...section,
                                    title: processedCount === 0 ? section.title : `${section.title} (Devam)`,
                                    content: chunk
                                });
                            }

                            processedCount += chunk.length;

                            // Eğer hala işlenecek veri varsa veya sayfa dolduysa -> Sayfayı Bitir
                            if (processedCount < content.length || currentHeight + chunk.length >= limit) {
                                // Mevcut sayfayı kaydet
                                newPages.push({
                                    ...originalPage,
                                    title: newPages.length === 0 ? originalPage.title : `${originalPage.title}`, // Sayfa numarası UI'da ekleniyor
                                    sections: JSON.parse(JSON.stringify(currentPageSections)) // Deep copy
                                });

                                // Yeni sayfa başlat
                                currentPageSections = [];
                                currentHeight = 0;
                            } else {
                                // Sayfa dolmadı, yüksekliği güncelle
                                currentHeight += chunk.length + headerCost;
                            }
                        }
                    }
                });

                // Kalan son parçaları ekle
                if (currentPageSections.length > 0) {
                    newPages.push({
                        ...originalPage,
                        title: originalPage.title,
                        sections: currentPageSections
                    });
                }
                return; 
            }

            // --- STRATEJİ 2: FLAT LISTS (ESKİ TİP AKTİVİTELER) ---
            // Genellikle sadece 1 ana dizi olur (örn: questions)
            const mainKey = splitKeys[0]; 
            const allItems = originalPage[mainKey];

            // Eğer limitin altındaysa bölmeye gerek yok
            if (allItems.length <= limit) {
                newPages.push(originalPage);
                return;
            }

            // Bölme işlemi
            for (let i = 0; i < allItems.length; i += limit) {
                const chunk = allItems.slice(i, i + limit);

                // Deep Copy yaparak referans sorunlarını çözüyoruz
                // Diğer anahtarları (varsa instructions, title vb.) koruyoruz
                const newPage = {
                    ...originalPage,
                    [mainKey]: chunk,
                    // İlk sayfa hariç diğerlerinde başlığa ek yapabiliriz (Opsiyonel, şu an kapalı)
                    // title: i === 0 ? originalPage.title : `${originalPage.title}` 
                };

                newPages.push(newPage);
            }
        });

        return newPages;
    }
};

import React, { useMemo } from 'react';
import { ShapeType, BaseActivityData } from '../../types';
import { EMOJI_MAP, simpleSyllabify } from '../../services/offlineGenerators/helpers';
import { EditableElement, EditableText } from '../Editable'; 

// --- COLOR CONSTANTS FOR 5W1H (Moved from ReadingStudio) ---
export const QUESTION_TYPES: Record<string, { label: string; color: string; bg: string; border: string }> = {
    who: { label: 'KİM?', color: '#ef4444', bg: '#fef2f2', border: '#fecaca' },     // Red
    what: { label: 'NE?', color: '#3b82f6', bg: '#eff6ff', border: '#bfdbfe' },      // Blue
    where: { label: 'NEREDE?', color: '#10b981', bg: '#ecfdf5', border: '#a7f3d0' }, // Green
    when: { label: 'NE ZAMAN?', color: '#f59e0b', bg: '#fffbeb', border: '#fde68a' },// Amber
    why: { label: 'NEDEN?', color: '#a855f7', bg: '#faf5ff', border: '#e9d5ff' },    // Purple
    how: { label: 'NASIL?', color: '#06b6d4', bg: '#ecfeff', border: '#a5f3fc' },    // Cyan
};

// --- HELPER COMPONENT: HIGHLIGHTED STORY (Moved from ReadingStudio) ---
export const StoryHighlighter = ({ text, highlights }: { text: string; highlights: { text: string; type: string }[] }) => {
    // If no text or highlights, return plain
    if (!text) return null;
    if (!highlights || highlights.length === 0) return <EditableText value={text} tag="div" />;

    // Sort highlights by length (descending) to match longest phrases first
    const sortedHighlights = [...highlights].sort((a, b) => b.text.length - a.text.length);

    // Escape regex characters
    const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    // Create a regex pattern
    const pattern = new RegExp(`(${sortedHighlights.map(h => escapeRegExp(h.text)).join('|')})`, 'gi');

    const parts = text.split(pattern);

    return (
        <div className="leading-relaxed text-justify">
            {parts.map((part, index) => {
                const highlight = sortedHighlights.find(h => h.text.toLowerCase() === part.toLowerCase());
                if (highlight) {
                    const style = QUESTION_TYPES[highlight.type];
                    return (
                        <span 
                            key={index} 
                            className="px-1 py-0.5 rounded mx-0.5 font-bold border-b-2"
                            style={{ 
                                backgroundColor: style?.bg || '#f3f4f6', 
                                color: style?.color || 'black',
                                borderColor: style?.color || 'transparent'
                            }}
                        >
                            {part}
                        </span>
                    );
                }
                return <span key={index}>{part}</span>;
            })}
        </div>
    );
};

// --- HELPER FUNCTIONS ---

const findEmojiForDescription = (desc: string): string | null => {
    if (!desc) return null;
    const safeDesc = String(desc);
    if (EMOJI_MAP[safeDesc]) return EMOJI_MAP[safeDesc]; 
    return null;
};

// --- CORE VISUAL COMPONENTS ---

interface ImageDisplayProps {
    base64?: string;
    description?: string | number;
    prompt?: string;
    className?: string;
}

export const ImageDisplay = React.memo(({ base64, description, prompt, className = "w-full h-24" }: ImageDisplayProps) => {
    let safeDesc = '';
    try { if (description) safeDesc = String(description); } catch (e) { safeDesc = ''; }

    const seed = useMemo(() => safeDesc.length > 0 ? safeDesc.split('').reduce((a, b) => a + b.charCodeAt(0), 0) : Math.floor(Math.random() * 1000), [safeDesc]);

    return (
        <div className={`image-display-container ${className} relative overflow-hidden bg-transparent flex items-center justify-center group`}>
            {safeDesc && (
                <div className="absolute bottom-0 left-0 right-0 bg-white/80 p-1 text-[8px] text-center opacity-0 group-hover:opacity-100 transition-opacity z-10 edit-handle pointer-events-none">
                    <EditableText value={safeDesc} tag="span" />
                </div>
            )}

            {(() => {
                if (base64 && typeof base64 === 'string' && (base64.trim().startsWith('<svg') || base64.trim().startsWith('<?xml') || base64.includes('</svg>'))) {
                    let cleanSvg = base64.replace(/^```xml\s*|```\s*$/g, '').replace(/^```svg\s*|```\s*$/g, '').trim();
                    cleanSvg = cleanSvg.replace(/\s+width="[^"]*"/gi, '').replace(/\s+height="[^"]*"/gi, '');
                    if (cleanSvg.includes('style="')) {
                        cleanSvg = cleanSvg.replace('style="', 'style="width:100%; height:100%; display:block; ');
                    } else {
                        cleanSvg = cleanSvg.replace('<svg', '<svg style="width:100%; height:100%; display:block;"');
                    }
                    return <div className="w-full h-full p-1 flex items-center justify-center" dangerouslySetInnerHTML={{ __html: cleanSvg }} />;
                }

                if (base64 && typeof base64 === 'string' && (base64.startsWith('data:image') || base64.length > 100)) { 
                    return <img src={base64} alt={safeDesc} className="object-contain w-full h-full" loading="lazy" />;
                }

                let contentForPrompt = prompt || safeDesc;
                if (contentForPrompt && contentForPrompt.length > 1) {
                    const finalPrompt = `${contentForPrompt}, educational vector illustration, simple black and white line art, white background, high contrast, minimalist`;
                    const encodedPrompt = encodeURIComponent(finalPrompt);
                    const imageUrl = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=512&height=512&nologo=true&seed=${seed}&model=flux`;

                    return (
                        <img 
                            src={imageUrl} 
                            alt={safeDesc} 
                            className="object-contain w-full h-full mix-blend-multiply" 
                            loading="lazy"
                        />
                    );
                }

                return (
                    <div className="flex flex-col items-center justify-center h-full w-full border border-dashed border-zinc-300 rounded text-zinc-300">
                        <span className="text-xl font-bold opacity-50">
                            <EditableText value={safeDesc ? safeDesc.charAt(0).toUpperCase() : '?'} tag="span" />
                        </span>
                    </div>
                );
            })()}
        </div>
    );
});

// --- PROCEDURAL SVG ENGINE ---

// 1. Dyslexic Text Engine (Bionic & Rainbow)
export const DyslexicText: React.FC<{ 
    text: string; 
    mode?: 'standard' | 'bionic' | 'rainbow'; 
    className?: string 
}> = ({ text, mode = 'standard', className = "" }) => {
    if (!text) return null;

    if (mode === 'standard') {
        return <span className={className}><EditableText value={text} tag="span" /></span>;
    }

    const words = text.split(' ');

    if (mode === 'bionic') {
        return (
            <div className={`leading-relaxed tracking-wide ${className}`}>
                {words.map((word, i) => {
                    const boldLen = Math.ceil(word.length / 2);
                    const boldPart = word.substring(0, boldLen);
                    const normalPart = word.substring(boldLen);
                    return (
                        <span key={i} className="inline-block mr-1.5">
                            <b className="font-black text-black">{boldPart}</b>
                            <span className="font-medium text-zinc-600">{normalPart}</span>
                        </span>
                    );
                })}
            </div>
        );
    }

    if (mode === 'rainbow') {
        return (
            <div className={`leading-loose tracking-wider ${className}`}>
                {words.map((word, i) => {
                    const syllables = simpleSyllabify(word);
                    return (
                        <span key={i} className="inline-block mr-2 bg-zinc-50 px-1 rounded">
                            {syllables.map((syl, j) => (
                                <span key={j} className={j % 2 === 0 ? "text-blue-600 font-bold" : "text-red-500 font-bold"}>
                                    {syl}
                                </span>
                            ))}
                        </span>
                    );
                })}
            </div>
        );
    }

    return null;
};

// 2. Handwriting & Tracing Engine (NEW)
