import { WorksheetData, ActivityType, StyleSettings } from '../types';

// A4 Sayfa Kapasitesi (Sanal Birim)
const MAX_PAGE_WEIGHT = 40;

// İçerik Türlerine Göre Ağırlık Puanları
const getWeight = (item: any): number => {
    if (!item) return 0;

    // Universal Schema Items
    if (item.type === 'image' || item.imagePrompt || item.imageBase64) return 12; // Resimler çok yer kaplar
    if (item.type === 'chart') return 12;
    if (item.type === 'code_block') return 8;
    if (item.type === 'table') {
        // Tablo başlığı + satır sayısı
        const rows = item.rows?.length || 0;
        return 4 + (rows * 1.5); 
    }
    if (item.type === 'shape_grid') return 10;
    if (item.type === 'key_value') return 3;
    if (item.type === 'question') return 4; // Soru + Şıklar

    // Standart Metinler
    if (item.text && item.text.length > 200) return 6; // Uzun metin
    if (item.text && item.text.length > 50) return 3;  // Orta metin

    // Varsayılan (Kısa liste öğesi vb.)
    return 2;
};

export const paginationService = {
    process: (data: WorksheetData, activityType: ActivityType, settings?: StyleSettings): WorksheetData => {
        // Veri yoksa veya boşsa döndür
        if (!data || !Array.isArray(data) || data.length === 0) return [];

        // Rapor ve Kitapçık türleri zaten özel render edildiği için dokunma
        if (activityType === 'WORKBOOK' || activityType === 'ASSESSMENT_REPORT') return data;

        const newPages: any[] = [];

        // Gelen her bir "Sayfa" verisini (jeneratörden gelen ham veri) analiz et
        // Genellikle jeneratörler tek bir büyük obje veya dizi döndürür.
        data.forEach((originalPageData, sourceIndex) => {

            // 1. Durum: Universal Schema (Sections & Content)
            if (originalPageData.sections && Array.isArray(originalPageData.sections)) {
                let currentPageSections: any[] = [];
                let currentWeight = 0;

                // Başlık alanı (Header) her sayfada yer kaplar (yaklaşık 5 birim)
                const headerWeight = 5;
                currentWeight += headerWeight;

                originalPageData.sections.forEach((section: any) => {
                    const sectionTitleWeight = section.title ? 2 : 0;

                    // Eğer bölümün kendisi boşsa atla
                    if (!section.content || !Array.isArray(section.content) || section.content.length === 0) return;

                    let currentSectionContent: any[] = [];

                    // Bölüm başlığı sığıyor mu?
                    if (currentWeight + sectionTitleWeight > MAX_PAGE_WEIGHT) {
                        // Sığmıyorsa mevcut sayfayı bitir
                        newPages.push({
                            ...originalPageData,
                            sections: currentPageSections,
                            isContinuation: newPages.length > 0 // Takip eden sayfalar için bayrak
                        });
                        currentPageSections = [];
                        currentWeight = headerWeight; // Yeni sayfa header payı
                    }

                    currentWeight += sectionTitleWeight;

                    // Bölüm içeriğini tek tek işle
                    section.content.forEach((item: any) => {
                        const w = getWeight(item);

                        // Eğer tek bir öğe sayfadan büyükse (örn: dev tablo), mecburen sığdığı kadarını koyacağız
                        // veya tek başına yeni sayfaya alacağız.

                        if (currentWeight + w > MAX_PAGE_WEIGHT) {
                            // Sayfa doldu, mevcut birikimi kaydet

                            // Mevcut bölümü kapat
                            if (currentSectionContent.length > 0) {
                                currentPageSections.push({
                                    ...section,
                                    content: currentSectionContent
                                });
                            }

                            // Sayfayı havuza at
                            newPages.push({
                                ...originalPageData,
                                title: originalPageData.title, // Başlığı koru
                                sections: currentPageSections,
                                isContinuation: true
                            });

                            // Yeni sayfa başlat
                            currentPageSections = [];
                            currentSectionContent = [];
                            currentWeight = headerWeight + sectionTitleWeight; // Header + Bölüm başlığı tekrarı

                            // Öğeyi yeni sayfaya ekle
                            currentSectionContent.push(item);
                            currentWeight += w;

                        } else {
                            // Sığıyorsa ekle
                            currentSectionContent.push(item);
                            currentWeight += w;
                        }
                    });

                    // Bölüm bittiğinde, kalan içerik varsa ekle
                    if (currentSectionContent.length > 0) {
                        currentPageSections.push({
                            ...section,
                            content: currentSectionContent,
                            // Eğer bu bölüm bir önceki sayfadan taştıysa başlığa "(Devam)" eklenebilir
                            // title: section.title 
                        });
                    }
                });

                // Son kalan sayfayı ekle
                if (currentPageSections.length > 0) {
                    newPages.push({
                        ...originalPageData,
                        sections: currentPageSections,
                        isContinuation: newPages.length > 0
                    });
                }

                return; // Bu veri tipi işlendi, sonraki loop'a geç
            }

            // 2. Durum: Eski Tip Listeler (Flat Arrays: questions, items, etc.)
            // Bu yapıda genellikle 'questions' veya 'items' gibi ana bir dizi vardır.
            const keysToCheck = ['questions', 'puzzles', 'items', 'patterns', 'operations', 'problems', 'rows'];
            let mainKey = keysToCheck.find(k => Array.isArray(originalPageData[k]) && originalPageData[k].length > 0);

            if (mainKey) {
                const allItems = originalPageData[mainKey];
                const itemsPerPage = getItemLimit(activityType);

                // Basit dilimleme (Slice)
                for (let i = 0; i < allItems.length; i += itemsPerPage) {
                    const chunk = allItems.slice(i, i + itemsPerPage);
                    newPages.push({
                        ...originalPageData,
                        [mainKey]: chunk,
                        pageNumber: (i / itemsPerPage) + 1,
                        totalPages: Math.ceil(allItems.length / itemsPerPage)
                    });
                }
                return;
            }

            // 3. Durum: Hiçbir yapıya uymayan veriler (olduğu gibi ekle)
            newPages.push(originalPageData);
        });

        return newPages;
    }
};

// Eski tip aktiviteler için sabit limitler (Fallback)
const getItemLimit = (type: ActivityType): number => {
    switch (type) {
        case 'BASIC_OPERATIONS': return 25;
        case 'MATH_PUZZLE': return 6;
        case 'NUMBER_PATTERN': return 10;
        case 'FUTOSHIKI': return 2; // Büyük kareler
        case 'SUDOKU': return 2;
        case 'VISUAL_MEMORY': return 6;
        case 'FIND_THE_DIFFERENCE': return 4;
        case 'SHAPE_MATCHING': return 5;
        case 'WORD_SEARCH': return 1; // Genelde 1 sayfa
        case 'CROSSWORD': return 1;
        default: return 8;
    }
};

import React from 'react';
import { ActivityType, SingleWorksheetData } from '../types';
import { PedagogicalHeader, ImageDisplay, GridComponent, ConnectionDot } from './sheets/common';
