            if (mainKey) {
                const allItems = originalPageData[mainKey];
                const itemsPerPage = getItemLimit(activityType);

                // Basit dilimleme (Slice)
                for (let i = 0; i < allItems.length; i += itemsPerPage) {
                    const chunk = allItems.slice(i, i + itemsPerPage);
                    newPages.push({
                        ...originalPageData,
                        [mainKey]: chunk,
                        pageNumber: (i / itemsPerPage) + 1,
                        totalPages: Math.ceil(allItems.length / itemsPerPage)
                    });
                }
                return;
            }

            // 3. Durum: Hiçbir yapıya uymayan veriler (olduğu gibi ekle)
            newPages.push(originalPageData);
        });

        return newPages;
    }
};

// Eski tip aktiviteler için sabit limitler (Fallback)
const getItemLimit = (type: ActivityType): number => {
    switch (type) {
        case 'BASIC_OPERATIONS': return 25;
        case 'MATH_PUZZLE': return 6;
        case 'NUMBER_PATTERN': return 10;
        case 'FUTOSHIKI': return 2; // Büyük kareler
        case 'SUDOKU': return 2;
        case 'VISUAL_MEMORY': return 6;
        case 'FIND_THE_DIFFERENCE': return 4;
        case 'SHAPE_MATCHING': return 5;
        case 'WORD_SEARCH': return 1; // Genelde 1 sayfa
        case 'CROSSWORD': return 1;
        default: return 8;
    }
};

