import { WorksheetData, ActivityType, StyleSettings } from '../types';

/**
 * Sayfa Kapasite Mantığı Güncellemesi:
 * Kullanıcının talebi üzerine içeriklerin kesilmesini önlemek için 
 * sayfalama motoru artık daha "cömert" davranıyor. 
 * Eğer bir bölüm tek başına çok uzunsa onu bölmek yerine tek bir uzun sayfada tutuyoruz.
 */

// Sayfa Kapasitesi (Sanal Birim) - Biraz artırıldı
const MAX_PAGE_WEIGHT = 48; 

const getWeight = (item: any): number => {
    if (!item) return 0;

    // Resimler ve Grafikler
    if (item.type === 'image' || item.imagePrompt || item.imageBase64) return 12;
    if (item.type === 'chart') return 10;
    if (item.type === 'code_block') return 8;

    // Tablolar (Satır bazlı ağırlık)
    if (item.type === 'table') {
        const rows = item.rows?.length || 0;
        return 6 + (rows * 1.8); 
    }

    if (item.type === 'shape_grid') return 10;
    if (item.type === 'key_value') return 3;

    // Sorular ve Metinler
    if (item.type === 'question') return 4; 
    if (item.text) {
        if (item.text.length > 500) return 12; // Çok uzun metin
        if (item.text.length > 200) return 6;
        return 3;
    }

    return 2;
};

export const paginationService = {
    process: (data: WorksheetData, activityType: ActivityType, settings?: StyleSettings): WorksheetData => {
        if (!data || !Array.isArray(data) || data.length === 0) return [];

        // Bu türlerde sayfalama yapma, özel renderları var
        if (activityType === 'WORKBOOK' || activityType === 'ASSESSMENT_REPORT') return data;

        // EĞER SMART PAGINATION KAPALIYSA: Her veriyi tek bir sayfaya bas (Kullanıcının asıl istediği bu olabilir)
        if (settings && settings.smartPagination === false) {
            return data;
        }

        const newPages: any[] = [];

        data.forEach((originalPageData) => {
            // Universal Schema (Sections)
            if (originalPageData.sections && Array.isArray(originalPageData.sections)) {
                let currentPageSections: any[] = [];
                let currentWeight = 0;
                const headerWeight = 8; // Header + Footer payı
                currentWeight += headerWeight;

                originalPageData.sections.forEach((section: any) => {
                    const sectionTitleWeight = section.title ? 3 : 0;

                    if (!section.content || !Array.isArray(section.content) || section.content.length === 0) return;

                    let currentSectionContent: any[] = [];

                    // Bölüm başlığı sığıyor mu?
                    if (currentWeight + sectionTitleWeight > MAX_PAGE_WEIGHT && currentPageSections.length > 0) {
                        newPages.push({
                            ...originalPageData,
                            sections: currentPageSections,
                            isContinuation: newPages.length > 0
                        });
                        currentPageSections = [];
                        currentWeight = headerWeight;
                    }

                    currentWeight += sectionTitleWeight;

                    section.content.forEach((item: any) => {
                        const w = getWeight(item);

                        // Eğer öğe mevcut sayfaya sığmıyorsa ve sayfada zaten bir şeyler varsa yeni sayfaya geç
                        if (currentWeight + w > MAX_PAGE_WEIGHT && (currentPageSections.length > 0 || currentSectionContent.length > 0)) {
                            if (currentSectionContent.length > 0) {
                                currentPageSections.push({ ...section, content: currentSectionContent });
                            }

                            newPages.push({
                                ...originalPageData,
                                sections: currentPageSections,
                                isContinuation: true
                            });

                            currentPageSections = [];
                            currentSectionContent = [];
                            currentWeight = headerWeight + sectionTitleWeight;
                        }

                        currentSectionContent.push(item);
                        currentWeight += w;
                    });

                    if (currentSectionContent.length > 0) {
                        currentPageSections.push({ ...section, content: currentSectionContent });
                        currentSectionContent = [];
                    }
                });

                if (currentPageSections.length > 0) {
                    newPages.push({
                        ...originalPageData,
                        sections: currentPageSections,
                        isContinuation: newPages.length > 0
                    });
                }
                return;
            }

            // Eski Tip Listeler
            const keysToCheck = ['questions', 'puzzles', 'items', 'patterns', 'operations', 'problems', 'rows'];
            let mainKey = keysToCheck.find(k => Array.isArray(originalPageData[k]) && originalPageData[k].length > 0);

            if (mainKey) {
                const allItems = originalPageData[mainKey];
                const itemsPerPage = getItemLimit(activityType);

                for (let i = 0; i < allItems.length; i += itemsPerPage) {
                    const chunk = allItems.slice(i, i + itemsPerPage);
                    newPages.push({
                        ...originalPageData,
                        [mainKey]: chunk,
                        isContinuation: i > 0,
                        pageNumber: (i / itemsPerPage) + 1
                    });
                }
                return;
            }

            newPages.push(originalPageData);
        });

        return newPages;
    }
};

const getItemLimit = (type: ActivityType): number => {
    switch (type) {
        case 'BASIC_OPERATIONS': return 30;
        case 'MATH_PUZZLE': return 12;
        case 'NUMBER_PATTERN': return 15;
        case 'SUDOKU': return 4;
        case 'WORD_SEARCH': return 1;
        default: return 12;
    }
};

