import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { InteractiveStoryData, ReadingStudioConfig } from '../../types';

export const generateInteractiveStory = async (config: ReadingStudioConfig): Promise<InteractiveStoryData> => {

    let questionInstructions = `
    [SORU YAPILANDIRMASI -Bloom Taksonomisi]:
    1. Bilgi: ${config.include5N1K ? '5N1K (Kim, Ne, Nerede, Ne Zaman, Nasıl, Neden) sorularını metin içinden birebir cevaplarla oluştur.' : 'Bu bölümü atla.'}
    2. Kavrama: ${config.countTrueFalse} adet Doğru/Yanlış sorusu oluştur.
    3. Uygulama: ${config.countFillBlanks} adet boşluk doldurma (metinden seçilen anahtar cümleler).
    4. Analiz/Sentez: ${config.countMultipleChoice} adet çoktan seçmeli (4 şıklı, derin anlam içeren) soru.
    5. Değerlendirme/Çıkarım: ${config.countLogic} adet mantık ve ${config.countInference} adet metin dışı çıkarım (inference) sorusu.
    `;

    const prompt = `
    [ROL: KIDEMLİ EĞİTİM PSİKOLOĞU VE İÇERİK TASARIMCISI]

    GÖREV: ${config.gradeLevel} seviyesindeki bir çocuk için ${config.genre} türünde, ${config.tone} tonda profesyonel bir okuma anlama materyali üret.

    KONU: ${config.topic || 'Öğretici ve Eğlenceli bir hikaye'}
    UZUNLUK: ${config.length === 'short' ? '60-90' : config.length === 'long' ? '250-400' : '150-200'} kelime.

    ${questionInstructions}

    EK GEREKSİNİMLER:
    - ${config.focusVocabulary ? 'Zorlayıcı 4 kelimeyi "vocabulary" alanına ekle.' : ''}
    - ${config.includeCreativeTask ? 'Hikayeyi pekiştiren bir "creativeTask" yaz.' : ''}
    - Hikayeyi anlamlı paragraflara (segments) böl.
    - SADECE geçerli JSON döndür.
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            story: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            mainIdea: { type: Type.STRING },
            segments: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { id: { type: Type.STRING }, text: { type: Type.STRING } },
                    required: ['id', 'text']
                }
            },
            vocabulary: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { word: { type: Type.STRING }, definition: { type: Type.STRING } },
                    required: ['word', 'definition']
                }
            },
            creativeTask: { type: Type.STRING },
            fiveW1H: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { 
                        type: { type: Type.STRING, enum: ['who', 'where', 'when', 'what', 'why', 'how'] },
                        question: { type: Type.STRING },
                        answer: { type: Type.STRING }
                    },
                    required: ['type', 'question', 'answer']
                }
            },
            multipleChoice: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING }
                    },
                    required: ['question', 'options', 'answer']
                }
            },
            trueFalse: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.BOOLEAN } },
                    required: ['question', 'answer']
                }
            },
            fillBlanks: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { sentence: { type: Type.STRING }, answer: { type: Type.STRING } },
                    required: ['sentence', 'answer']
                }
            },
            logicQuestions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.STRING }, hint: { type: Type.STRING } },
                    required: ['question', 'answer', 'hint']
                }
            }
        },
        required: ['title', 'story', 'segments', 'fiveW1H']
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
    return {
        ...result,
        gradeLevel: config.gradeLevel,
        genre: config.genre,
        wordCount: result.story.split(' ').length
    };
};

