                                    <button onClick={() => setLayout(prev => prev.map(l => l.id === item.id ? {...l, isVisible: !l.isVisible} : l))} className="text-zinc-400 hover:text-indigo-600">
                                        <i className={`fa-solid ${item.isVisible ? 'fa-eye' : 'fa-eye-slash'}`}></i>
                                    </button>
