                         <div className="flex gap-2">
                             <button onClick={() => printService.generatePdf('.reading-page', 'Okuma Çalışması', {action: 'print'})} className="px-4 py-2 bg-zinc-900 text-white rounded-lg font-bold text-xs"><i className="fa-solid fa-print"></i> Yazdır</button>
                         </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-12 bg-zinc-100 flex justify-center custom-scrollbar">
                        <div className="reading-page worksheet-page print-page bg-white shadow-2xl p-[15mm] flex flex-col" style={{ width: '210mm', minHeight: '297mm', height: 'auto' }}>
                             {layout.filter(l => l.isVisible).map(item => renderPreviewBlock(item))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import { WorksheetData, ActivityType, StyleSettings } from '../types';

/**
 * Sayfa Kapasite Mantığı Güncellemesi:
 * Dinamik A4 yapısında 'height: auto' kullanıldığı için,
 * paginationService sadece veri bloklarını ayırmak için bir 'mantıksal seperatör' görevi görür.
 */

const MAX_PAGE_WEIGHT = 45; 

const getWeight = (item: any): number => {
    if (!item) return 0;
    if (item.type === 'image' || item.imagePrompt || item.imageBase64) return 15;
    if (item.type === 'table') return 10 + ((item.rows?.length || 0) * 2);
    if (item.type === 'chart') return 12;
    if (item.text && item.text.length > 300) return 10;
    return 5;
};

export const paginationService = {
    process: (data: WorksheetData, activityType: ActivityType, settings?: StyleSettings): WorksheetData => {
        if (!data || !Array.isArray(data) || data.length === 0) return [];

        // Okuma Stüdyosu içerikleri tek bir akışkan sayfada gösterilmeli (Print-auto-height)
        if (activityType === 'STORY_COMPREHENSION') return data;

        const newPages: any[] = [];
        data.forEach((originalPageData) => {
            if (originalPageData.sections && Array.isArray(originalPageData.sections)) {
                let currentPageSections: any[] = [];
                let currentWeight = 0;

                originalPageData.sections.forEach((section: any) => {
                    const sectionWeight = (section.content || []).reduce((acc: number, item: any) => acc + getWeight(item), 5);

                    if (currentWeight + sectionWeight > MAX_PAGE_WEIGHT && currentPageSections.length > 0) {
                        newPages.push({ ...originalPageData, sections: currentPageSections, isContinuation: newPages.length > 0 });
                        currentPageSections = [];
                        currentWeight = 0;
                    }
                    currentPageSections.push(section);
                    currentWeight += sectionWeight;
                });

                if (currentPageSections.length > 0) {
                    newPages.push({ ...originalPageData, sections: currentPageSections, isContinuation: newPages.length > 0 });
                }
            } else {
                newPages.push(originalPageData);
            }
        });

        return newPages;
    }
};

