export interface InteractiveStoryData extends BaseActivityData { 
    story: string; 
    segments: { id: string; text: string; }[]; 
    genre: string;
    gradeLevel: string;
    wordCount: number;

    // Components
    fiveW1H: { question: string; answer: string; type: string }[];
    multipleChoice: { question: string; options: string[]; answer: string }[];
    trueFalse: { question: string; answer: boolean }[];
    fillBlanks: { sentence: string; answer: string }[];
    logicQuestions: { question: string; answer: string; hint: string }[];

    vocabulary: VocabularyItem[]; 
    creativeTask: string; 
    mainIdea: string;
    imagePrompt: string;

    // Compatibility
    answers?: any[];
}

export interface ReadingStudioConfig {
    gradeLevel: string;
    studentName: string;
    topic: string;
    genre: string;
    tone: string;
    length: 'short' | 'medium' | 'long';
    layoutDensity: 'comfortable' | 'compact';

    // Image Controls
    includeImage: boolean;
    imageScale: number; // 20 - 100 percentage
    imagePosition: 'top' | 'left' | 'right';

    // Advanced Question Structure
    include5N1K: boolean;
    countMultipleChoice: number;
    countTrueFalse: number;
    countFillBlanks: number;
    countLogic: number;

    // Modules
    focusVocabulary: boolean;
    includeCreativeTask: boolean;
    showReadingTracker: boolean;
    showSelfAssessment: boolean;
    showTeacherNotes: boolean;
    showDateSection: boolean;
}

import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { InteractiveStoryData, ReadingStudioConfig } from '../../types';

export const generateInteractiveStory = async (config: ReadingStudioConfig): Promise<InteractiveStoryData> => {

    let questionInstructions = `
    [SORU YAPILANDIRMASI -Bloom Taksonomisi Odaklı]:
    1. Bilgi Seviyesi: ${config.include5N1K ? 'Metin içinden birebir cevapları olan 5N1K soruları oluştur.' : 'Bu bölümü atla.'}
    2. Kavrama: ${config.countTrueFalse} adet Doğru/Yanlış sorusu.
    3. Uygulama: ${config.countFillBlanks} adet boşluk doldurma (metindeki kritik cümleleri kullan).
    4. Analiz/Sentez: ${config.countMultipleChoice} adet çoktan seçmeli (4 şıklı) soru.
    5. Değerlendirme: ${config.countLogic} adet mantık/çıkarım sorusu.
    `;

    const prompt = `
    [ROL: KIDEMLİ EĞİTİM PSİKOLOĞU VE İÇERİK TASARIMCISI]

    GÖREV: ${config.gradeLevel} seviyesinde bir çocuk için ${config.genre} türünde, ${config.tone} tonda profesyonel bir okuma anlama materyali üret.

    KONU: ${config.topic || 'Yaratıcı bir konu'}
    UZUNLUK: ${config.length === 'short' ? '60-90' : config.length === 'long' ? '250-350' : '150-200'} kelime.

    ${questionInstructions}

    EK GEREKSİNİMLER:
    - ${config.focusVocabulary ? 'Öğrenilmesi gereken 4 kelimeyi "vocabulary" alanına ekle.' : ''}
    - ${config.includeCreativeTask ? 'Hikaye ile bağlantılı bir "creativeTask" yaz.' : ''}
    - Hikayeyi anlamlı paragraflara (segments) böl.
    - SADECE geçerli JSON döndür.
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            story: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            mainIdea: { type: Type.STRING },
            segments: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { id: { type: Type.STRING }, text: { type: Type.STRING } },
                    required: ['id', 'text']
                }
            },
            vocabulary: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { word: { type: Type.STRING }, definition: { type: Type.STRING } },
                    required: ['word', 'definition']
                }
            },
            creativeTask: { type: Type.STRING },
            fiveW1H: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { 
                        type: { type: Type.STRING, enum: ['who', 'where', 'when', 'what', 'why', 'how'] },
                        question: { type: Type.STRING },
                        answer: { type: Type.STRING }
                    },
                    required: ['type', 'question', 'answer']
                }
            },
            multipleChoice: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING }
                    },
                    required: ['question', 'options', 'answer']
                }
            },
            trueFalse: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.BOOLEAN } },
                    required: ['question', 'answer']
                }
            },
            fillBlanks: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { sentence: { type: Type.STRING }, answer: { type: Type.STRING } },
                    required: ['sentence', 'answer']
                }
            },
            logicQuestions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.STRING }, hint: { type: Type.STRING } },
                    required: ['question', 'answer', 'hint']
                }
            }
        },
        required: ['title', 'story', 'segments', 'fiveW1H', 'imagePrompt']
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
    return {
        ...result,
        gradeLevel: config.gradeLevel,
        genre: config.genre,
        wordCount: result.story.split(' ').length
    };
};

