import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { InteractiveStoryData, ReadingStudioConfig } from '../../types';

export const generateInteractiveStory = async (config: ReadingStudioConfig): Promise<InteractiveStoryData> => {

    let bloomInstructions = `
    [SORU YAPILANDIRMASI - PROFESYONEL EĞİTİM STRATEJİSİ]:
    1. Bilgi (Remembering): ${config.include5N1K ? 'Metindeki olguları sorgulayan 5N1K soruları üret. Cevaplar metinden birebir alıntılanabilir olmalı.' : 'Atla.'}
    2. Kavrama (Understanding): ${config.countTrueFalse} adet Doğru/Yanlış ve ${config.countFillBlanks} adet boşluk doldurma sorusu üret.
    3. Analiz/Çıkarım (Analyzing): ${config.countInference} adet metin dışı çıkarım (Inference) sorusu üret. Öğrenci "satır aralarını" okumalı.
    4. Değerlendirme (Evaluating): ${config.countLogic} adet mantık sorusu üret. Karakterlerin kararlarını veya olayların nedenlerini sorgula.
    5. Uygulama/Sentez: ${config.countMultipleChoice} adet derinlikli çoktan seçmeli soru.

    [ÖZEL MÜDAHALE GÖREVLERİ]:
    - ${config.includeWordHunt ? 'Metin içinden seçilen 3 kelime için "Harf Avı" sorusu ekle.' : ''}
    - ${config.includeSpellingCheck ? 'Metindeki 2 anahtar kelimenin doğru/yanlış yazımını sorgula.' : ''}
    `;

    const prompt = `
    [ROL: KIDEMLİ EĞİTİM PSİKOLOĞU VE DİSLEKSİ UZMANI]

    GÖREV: ${config.gradeLevel} seviyesindeki bir çocuk için ${config.genre} türünde, ${config.tone} tonda zenginleştirilmiş bir okuma-anlama seti üret.

    KONU: ${config.topic || 'Yaratıcı ve ilham verici bir hikaye'}
    METİN HEDEFİ: ${config.length === 'short' ? '70-100 kelime' : config.length === 'long' ? '300-450 kelime' : '150-220 kelime'}.

    ${bloomInstructions}

    EK GEREKSİNİMLER:
    - Hikayeyi disleksi dostu kısa ve net cümlelerle yaz.
    - "vocabulary" alanına ${config.focusVocabulary ? '4 adet' : '0'} akademik/yeni kelime ve çocuk diliyle tanım ekle.
    - "imagePrompt" için hikayenin atmosferini yansıtan detaylı, İngilizce bir betimleme yaz.
    - SADECE JSON döndür.
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            story: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            mainIdea: { type: Type.STRING },
            segments: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { id: { type: Type.STRING }, text: { type: Type.STRING } },
                    required: ['id', 'text']
                }
            },
            vocabulary: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { word: { type: Type.STRING }, definition: { type: Type.STRING } },
                    required: ['word', 'definition']
                }
            },
            creativeTask: { type: Type.STRING },
            fiveW1H: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { 
                        type: { type: Type.STRING, enum: ['who', 'where', 'when', 'what', 'why', 'how'] },
                        question: { type: Type.STRING },
                        answer: { type: Type.STRING }
                    },
                    required: ['type', 'question', 'answer']
                }
            },
            multipleChoice: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: { type: Type.STRING },
                        options: { type: Type.ARRAY, items: { type: Type.STRING } },
                        answer: { type: Type.STRING }
                    },
                    required: ['question', 'options', 'answer']
                }
            },
            trueFalse: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.BOOLEAN } },
                    required: ['question', 'answer']
                }
            },
            fillBlanks: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { sentence: { type: Type.STRING }, answer: { type: Type.STRING } },
                    required: ['sentence', 'answer']
                }
            },
            logicQuestions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.STRING }, hint: { type: Type.STRING } },
                    required: ['question', 'answer', 'hint']
                }
            },
            inferenceQuestions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { question: { type: Type.STRING }, answer: { type: Type.STRING } },
                    required: ['question', 'answer']
                }
            },
            interventionQuestions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: { 
                        question: { type: Type.STRING }, 
                        type: { type: Type.STRING, enum: ['word_hunt', 'spelling', 'visual_memory'] } 
                    },
                    required: ['question', 'type']
                }
            }
        },
        required: ['title', 'story', 'segments', 'fiveW1H', 'vocabulary']
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-pro-preview');
    return {
        ...result,
        gradeLevel: config.gradeLevel,
        genre: config.genre,
        wordCount: result.story.split(' ').length
    };
};

