export const ReadingStudio: React.FC<any> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [view, setView] = useState<'cms' | 'preview'>('cms');
    const [isLoading, setIsLoading] = useState(false);
    const [storyData, setStoryData] = useState<InteractiveStoryData | null>(null);
    const [layout, setLayout] = useState<LayoutItem[]>(DEFAULT_LAYOUT);

    const [config, setConfig] = useState<ReadingStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '', topic: '', genre: 'Macera', tone: 'Eğlenceli',
        length: 'medium', layoutDensity: 'comfortable', 
        includeImage: true, imageSize: 35, imagePosition: 'left', imageOpacity: 20,
        include5N1K: true, countMultipleChoice: 3, countTrueFalse: 2,
        countFillBlanks: 2, countLogic: 1, countInference: 1, 
        includeWordHunt: true, includeSpellingCheck: true, focusVocabulary: true,
        includeCreativeTask: true, showReadingTracker: true, showSelfAssessment: false,
        showTeacherNotes: false, showDateSection: true
    });

    const dragItem = useRef<number | null>(null);
    const dragOverItem = useRef<number | null>(null);

    const handleSort = () => {
        const _layout = [...layout];
        if (dragItem.current !== null && dragOverItem.current !== null) {
            const draggedItem = _layout.splice(dragItem.current, 1)[0];
            _layout.splice(dragOverItem.current, 0, draggedItem);
            setLayout(_layout);
        }
        dragItem.current = null;
        dragOverItem.current = null;
    };

    const handleGenerate = async () => {
        setIsLoading(true);
        try {
            const data = await generateInteractiveStory(config);
            setStoryData(data);
            setView('preview');
        } catch (e) { alert("Üretim hatası. Lütfen tekrar deneyin."); }
        finally { setIsLoading(false); }
    };

    const updateBlockHeight = (id: LayoutSectionId, delta: number) => {
        setLayout(prev => prev.map(item => 
            item.id === id ? { ...item, heightEstimate: Math.max(40, item.heightEstimate + delta) } : item
        ));
    };

    const handlePrint = async (action: 'print' | 'download') => {
        if (!storyData) return;
        try {
            await printService.generatePdf('.reading-studio-print-container', storyData.title, { action });
        } catch (error) {
            console.error("Print error", error);
        }
    };

    const renderPreviewBlock = (item: LayoutItem) => {
        if (!item.isVisible || !storyData) return null;

        return (
            <div 
                key={item.id} 
                className="relative border-2 border-transparent hover:border-indigo-400 group/block transition-all mb-4"
