// --- INTERACTIVE RESIZABLE BLOCK COMPONENT ---
interface InteractiveBlockProps {
    item: LayoutItem;
    children: React.ReactNode;
    isSelected: boolean;
    onSelect: () => void;
    onUpdateStyle: (id: LayoutSectionId, style: Partial<LayoutItem['style']>) => void;
    onMove: (id: LayoutSectionId, direction: 'up' | 'down') => void;
    designMode: boolean;
}

const InteractiveBlock: React.FC<InteractiveBlockProps> = ({ item, children, isSelected, onSelect, onUpdateStyle, onMove, designMode }) => {
    const blockRef = useRef<HTMLDivElement>(null);
    const isResizing = useRef(false);
    const startY = useRef(0);
    const startHeight = useRef(0);

    const handleMouseDown = (e: React.MouseEvent) => {
        if (!designMode) return;
        e.stopPropagation();
        isResizing.current = true;
        startY.current = e.clientY;
        startHeight.current = blockRef.current?.clientHeight || item.style.minHeight;

        const handleMouseMove = (moveEvent: MouseEvent) => {
            if (!isResizing.current) return;
            const deltaY = moveEvent.clientY - startY.current;
            const newHeight = Math.max(50, startHeight.current + deltaY);
            // Directly update DOM for smoothness, state update on mouse up
            if(blockRef.current) blockRef.current.style.minHeight = `${newHeight}px`;
        };

        const handleMouseUp = (upEvent: MouseEvent) => {
            isResizing.current = false;
            const deltaY = upEvent.clientY - startY.current;
            const newHeight = Math.max(50, startHeight.current + deltaY);
            onUpdateStyle(item.id, { minHeight: newHeight });

            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };

        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseup', handleMouseUp);
    };

    return (
        <div 
            ref={blockRef}
            onClick={(e) => { if(designMode) { e.stopPropagation(); onSelect(); } }}
            className={`relative transition-all duration-200 ${designMode ? 'cursor-pointer hover:ring-2 hover:ring-indigo-300' : ''} ${isSelected && designMode ? 'ring-2 ring-indigo-600 bg-indigo-50/10 z-10' : ''}`}
            style={{ 
                width: `${item.style.widthPercent}%`,
                minHeight: `${item.style.minHeight}px`,
                marginTop: `${item.style.marginTop}px`,
                marginBottom: `${item.style.marginBottom}px`,
                padding: `${item.style.padding}px`,
                border: designMode ? '1px dashed #e5e7eb' : 'none',
                position: 'relative'
            }}
        >
            {/* CONTENT */}
            <div className="w-full h-full relative">
                {children}
            </div>

            {/* DESIGN MODE CONTROLS */}
            {designMode && isSelected && (
                <>
                    {/* Move Handle (Top Right) */}
                    <div className="absolute -top-3 -right-3 flex gap-1 bg-white border border-zinc-200 shadow-sm rounded-lg p-1 z-50">
                        <button onClick={(e) => { e.stopPropagation(); onMove(item.id, 'up'); }} className="w-6 h-6 hover:bg-zinc-100 rounded flex items-center justify-center text-zinc-500"><i className="fa-solid fa-arrow-up"></i></button>
                        <button onClick={(e) => { e.stopPropagation(); onMove(item.id, 'down'); }} className="w-6 h-6 hover:bg-zinc-100 rounded flex items-center justify-center text-zinc-500"><i className="fa-solid fa-arrow-down"></i></button>
                        {/* Width Controls */}
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStyle(item.id, { widthPercent: Math.max(20, item.style.widthPercent - 10) }); }} className="w-6 h-6 hover:bg-zinc-100 rounded flex items-center justify-center text-zinc-500 text-xs">-W</button>
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStyle(item.id, { widthPercent: Math.min(100, item.style.widthPercent + 10) }); }} className="w-6 h-6 hover:bg-zinc-100 rounded flex items-center justify-center text-zinc-500 text-xs">+W</button>
                    </div>

                    {/* Resize Handle (Bottom Right) */}
                    <div 
                        onMouseDown={handleMouseDown}
                        className="absolute bottom-0 right-0 w-6 h-6 bg-indigo-500 cursor-ns-resize rounded-tl-lg flex items-center justify-center z-50 hover:scale-110 transition-transform"
                        title="Yüksekliği Ayarla"
                    >
                        <i className="fa-solid fa-up-down text-white text-[10px]"></i>
                    </div>

                    {/* Info Badge */}
                    <div className="absolute top-0 left-0 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-br font-mono opacity-50 pointer-events-none">
                        {item.label} (H:{item.style.minHeight}px)
                    </div>
                </>
            )}
        </div>
    );
};

export const ReadingStudio: React.FC<any> = ({ onBack, onAddToWorkbook }) => {
    const { user } = useAuth();
    const [view, setView] = useState<'cms' | 'preview'>('cms');
    const [isLoading, setIsLoading] = useState(false);
    const [storyData, setStoryData] = useState<InteractiveStoryData | null>(null);
    const [layout, setLayout] = useState<LayoutItem[]>(DEFAULT_LAYOUT);

    // Design Mode State
    const [designMode, setDesignMode] = useState(false);
    const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null);

    const [config, setConfig] = useState<ReadingStudioConfig>({
        gradeLevel: '3. Sınıf', studentName: '', topic: '', genre: 'Macera', tone: 'Eğlenceli',
        length: 'medium', layoutDensity: 'comfortable', 
        includeImage: true, imageSize: 35, imagePosition: 'left', imageOpacity: 20,
        include5N1K: true, countMultipleChoice: 3, countTrueFalse: 2,
        countFillBlanks: 2, countLogic: 1, countInference: 1, 
        includeWordHunt: true, includeSpellingCheck: true, focusVocabulary: true,
        includeCreativeTask: true, showReadingTracker: true, showSelfAssessment: false,
        showTeacherNotes: false, showDateSection: true
    });

    const handleGenerate = async () => {
        setIsLoading(true);
        try {
            const data = await generateInteractiveStory(config);
            setStoryData(data);
            setView('preview');
        } catch (e) { alert("Üretim hatası. Lütfen tekrar deneyin."); }
        finally { setIsLoading(false); }
    };

    const handlePrint = async (action: 'print' | 'download') => {
        if (!storyData) return;
        // Temporarily disable design mode for clean print
        const wasDesignMode = designMode;
        setDesignMode(false);
        setTimeout(async () => {
            try {
                await printService.generatePdf('.reading-studio-print-container', storyData.title, { action });
            } catch (error) {
                console.error("Print error", error);
            } finally {
                setDesignMode(wasDesignMode);
            }
        }, 100);
    };

    const updateBlockStyle = (id: LayoutSectionId, newStyle: Partial<LayoutItem['style']>) => {
        setLayout(prev => prev.map(item => item.id === id ? { ...item, style: { ...item.style, ...newStyle } } : item));
    };

    const moveBlock = (id: LayoutSectionId, direction: 'up' | 'down') => {
        const index = layout.findIndex(l => l.id === id);
        if (index === -1) return;

        const newLayout = [...layout];
        if (direction === 'up' && index > 0) {
            [newLayout[index], newLayout[index-1]] = [newLayout[index-1], newLayout[index]];
        } else if (direction === 'down' && index < newLayout.length - 1) {
            [newLayout[index], newLayout[index+1]] = [newLayout[index+1], newLayout[index]];
        }
        setLayout(newLayout);
    };

    const renderBlockContent = (id: LayoutSectionId) => {
        if (!storyData) return <div className="text-zinc-300 italic text-center p-4">İçerik bekleniyor...</div>;

        switch(id) {
            case 'header':
                return (
                    <div className="border-b-4 border-black pb-2 h-full flex flex-col justify-end">
                        <EditableText tag="h1" className="text-3xl font-black uppercase leading-none" value={storyData.title} />
                        <div className="flex justify-between items-end mt-1">
                            <p className="text-sm font-bold text-zinc-500 uppercase">{config.genre} • {config.gradeLevel}</p>
                            {config.showDateSection && <div className="text-[10px] font-bold text-zinc-400 border-b border-black w-24 text-right">Tarih</div>}
                        </div>
                    </div>
                );
            case 'story_block':
                return (
                    <div className={`relative h-full ${config.imagePosition === 'background' ? '' : 'flex gap-6'}`} 
                         style={{ flexDirection: config.imagePosition === 'right' ? 'row-reverse' : config.imagePosition === 'top' ? 'column' : 'row' }}>

                        {config.includeImage && (
                            <div 
                                className={`shrink-0 border-2 border-black rounded-xl overflow-hidden bg-zinc-50 transition-all ${config.imagePosition === 'background' ? 'absolute inset-0 z-0' : 'relative z-10'}`}
                                style={{ 
                                    width: (config.imagePosition === 'top' || config.imagePosition === 'background') ? '100%' : `${config.imageSize}%`,
                                    opacity: config.imagePosition === 'background' ? config.imageOpacity / 100 : 1,
                                    height: config.imagePosition === 'top' ? '200px' : 'auto',
                                    aspectRatio: config.imagePosition === 'top' ? 'auto' : '1'
                                }}
                            >
                                <ImageDisplay prompt={storyData.imagePrompt} description={storyData.title} className="w-full h-full object-cover grayscale" />
                            </div>
                        )}

                        <div className={`flex-1 text-justify font-serif leading-relaxed z-10 overflow-hidden ${config.imagePosition === 'background' ? 'p-4 bg-white/60 backdrop-blur-[1px]' : ''} ${config.layoutDensity === 'compact' ? 'text-base' : 'text-xl'}`}>
                            <StoryHighlighter text={storyData.story} highlights={(storyData.fiveW1H || []).map(q => ({ text: q.answer, type: q.type }))} />
                        </div>
                    </div>
                );
            case 'vocabulary':
                return storyData.vocabulary.length > 0 && (
                    <div className="h-full p-4 border-2 border-black bg-zinc-50 rounded-xl overflow-hidden">
                        <h4 className="font-black text-[10px] uppercase text-zinc-400 mb-2 border-b border-zinc-200">KELİME DAĞARCIĞI</h4>
                        <div className="grid grid-cols-2 gap-x-6 gap-y-2">
                             {storyData.vocabulary.map((v, i) => (
                                 <div key={i} className="text-xs">
                                     <span className="font-bold">{v.word}:</span> {v.definition}
                                 </div>
                             ))}
                        </div>
                    </div>
                );
            case 'questions_5n1k':
                return (
                    <div className="h-full overflow-hidden">
                        <h4 className="font-black border-b-2 border-black mb-2 text-sm">OKUDUĞUMU ANLIYORUM (5N1K)</h4>
                        <div className="space-y-3">
                            {storyData.fiveW1H.map((q, i) => (
                                <div key={i} className="text-sm">
                                    <div className="flex gap-2">
                                        <span className="shrink-0 px-2 py-0.5 rounded text-[10px] font-black text-white" style={{ backgroundColor: QUESTION_TYPES[q.type]?.color }}>{QUESTION_TYPES[q.type]?.label}</span>
                                        <p className="font-bold truncate">{q.question}</p>
                                    </div>
                                    <div className="border-b border-dashed border-zinc-400 h-6 w-full ml-1"></div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            case 'questions_inference':
                return storyData.inferenceQuestions.length > 0 && (
                    <div className="h-full overflow-hidden">
                        <h4 className="font-black border-b-2 border-black mb-2 text-sm flex items-center gap-2">
                             <i className="fa-solid fa-brain text-indigo-500"></i> DERİN DÜŞÜNÜYORUM
                        </h4>
                        <div className="space-y-3">
                            {storyData.inferenceQuestions.map((q, i) => (
                                <div key={i} className="text-sm">
                                    <p className="font-bold mb-1">Q: {q.question}</p>
                                    <div className="border-b border-dashed border-zinc-400 h-8 w-full"></div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            case 'questions_test':
                return (
                    <div className="h-full overflow-hidden grid grid-cols-2 gap-4">
                        <div>
                             <h4 className="font-black text-xs border-b border-black mb-2">DOĞRU / YANLIŞ</h4>
                             {storyData.trueFalse?.map((q, i) => (
                                 <div key={i} className="flex justify-between text-[10px] mb-1">
                                     <span className="truncate flex-1">{q.question}</span>
                                     <div className="flex gap-1 font-bold"><span>(D)</span><span>(Y)</span></div>
                                 </div>
                             ))}
                        </div>
                        <div>
                             <h4 className="font-black text-xs border-b border-black mb-2">TEST</h4>
                             {storyData.multipleChoice?.map((q, i) => (
                                 <div key={i} className="text-[10px] mb-2">
                                     <p className="font-bold truncate">{i+1}. {q.question}</p>
                                     <div className="flex gap-2 ml-2">
                                         {q.options.slice(0,3).map((o, k) => <span key={k} className="before:content-['○'] before:mr-1 truncate max-w-[60px]">{o}</span>)}
                                     </div>
                                 </div>
                             ))}
                        </div>
                    </div>
                );
            case 'creative':
                return storyData.creativeTask && (
                     <div className="h-full border-2 border-dashed border-zinc-400 rounded-xl p-4 text-center bg-indigo-50/50 relative">
                         <div className="absolute top-2 left-2 text-xs font-bold text-indigo-800 uppercase bg-white px-2 rounded">Yaratıcı Görev</div>
                         <p className="text-xs font-bold italic mt-6">"{storyData.creativeTask}"</p>
                         <div className="mt-4 text-zinc-300 text-4xl"><i className="fa-solid fa-paintbrush"></i></div>
                    </div>
                );
            case 'tracker':
                return (
                    <div className="flex items-center gap-4 h-full bg-zinc-50 rounded-lg px-4 border border-zinc-200">
                         <span className="text-[10px] font-bold uppercase tracking-widest text-zinc-500">Okuma Takibi:</span>
                         {[1,2,3].map(i => (
                             <div key={i} className="w-6 h-6 rounded-full border-2 border-zinc-300 bg-white"></div>
