                )
            default: return null;
        }
    }

    return (
        <div className="h-full flex flex-col bg-zinc-50 dark:bg-zinc-950 overflow-hidden">
            {view === 'cms' ? (
                <div className="flex h-full">
                    {/* SOL PANEL: AYARLAR */}
                    <div className="w-1/3 h-full overflow-y-auto p-6 border-r border-zinc-200 dark:border-zinc-800 custom-scrollbar">
                        <h2 className="text-xl font-black mb-6 flex items-center gap-2">
                            <i className="fa-solid fa-sliders text-indigo-500"></i> Stüdyo Ayarları
                        </h2>

                        <ConfigSection title="Hikaye Temelleri" icon="fa-book">
                            <input 
                                type="text" placeholder="Hikaye Konusu..."
                                value={config.topic} onChange={e => setConfig({...config, topic: e.target.value})}
                                className="w-full p-3 rounded-xl border border-zinc-300 dark:border-zinc-700 bg-white dark:bg-zinc-800 font-bold outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                            <div className="grid grid-cols-2 gap-2">
                                <select value={config.genre} onChange={e => setConfig({...config, genre: e.target.value})} className="p-2 border rounded-lg text-xs font-bold bg-white">
                                    <option>Masal</option><option>Macera</option><option>Bilim Kurgu</option><option>Fabl</option>
                                </select>
                                <select value={config.gradeLevel} onChange={e => setConfig({...config, gradeLevel: e.target.value})} className="p-2 border rounded-lg text-xs font-bold bg-white">
                                    <option>1. Sınıf</option><option>2. Sınıf</option><option>3. Sınıf</option><option>4. Sınıf</option>
                                </select>
                            </div>
                        </ConfigSection>

                        <ConfigSection title="Görsel & Yerleşim" icon="fa-image">
                            <label className="flex items-center justify-between text-xs font-bold">
                                <span>Görsel Eklensin mi?</span>
                                <input type="checkbox" checked={config.includeImage} onChange={e => setConfig({...config, includeImage: e.target.checked})} className="w-4 h-4 accent-indigo-600" />
                            </label>
                            {config.includeImage && (
                                <div className="space-y-4 pt-2 border-t mt-2">
                                    <div>
                                        <div className="flex justify-between text-[10px] font-bold text-zinc-400 uppercase mb-1">
