                                        </div>
                                        <input type="range" min="15" max="100" value={config.imageSize} onChange={e => setConfig({...config, imageSize: Number(e.target.value)})} className="w-full accent-indigo-600" />
                                    </div>
                                    <div className="grid grid-cols-5 gap-1">
                                        {(['left', 'right', 'top', 'center', 'background'] as const).map(p => (
                                            <button 
                                                key={p} onClick={() => setConfig({...config, imagePosition: p})}
