                                </label>
                                <div className="grid grid-cols-2 gap-3">
                                    <div><span className="text-[10px] text-zinc-400 font-bold">TEST SORUSU</span><input type="number" value={config.countMultipleChoice} onChange={e => setConfig({...config, countMultipleChoice: Number(e.target.value)})} className="w-full p-2 border rounded text-xs font-bold" /></div>
                                    <div><span className="text-[10px] text-zinc-400 font-bold">DOĞRU / YANLIŞ</span><input type="number" value={config.countTrueFalse} onChange={e => setConfig({...config, countTrueFalse: Number(e.target.value)})} className="w-full p-2 border rounded text-xs font-bold" /></div>
                                    <div><span className="text-[10px] text-zinc-400 font-bold">ÇIKARIM (ANALİZ)</span><input type="number" value={config.countInference} onChange={e => setConfig({...config, countInference: Number(e.target.value)})} className="w-full p-2 border rounded text-xs font-bold" /></div>
