                             <button onClick={() => handlePrint('print')} className="px-5 py-2 bg-zinc-900 text-white rounded-xl font-bold text-xs hover:bg-black shadow-md transition-all active:scale-95"><i className="fa-solid fa-print mr-2"></i> Yazdır</button>
