                         </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-12 bg-zinc-100 flex justify-center custom-scrollbar">
                        {/* A4 PAPER - PRINT CONTAINER */}
                        <div className="reading-studio-print-container print-auto-height bg-white shadow-2xl p-[20mm] relative flex flex-col" style={{ width: '210mm', minHeight: '297mm', height: 'auto' }}>
                             {layout.filter(l => l.isVisible).map(item => (
                                 <div 
                                    key={item.id} 
                                    style={{
                                        width: `${item.style.widthPercent}%`,
                                        minHeight: `${item.style.minHeight}px`,
