interface ResizeHandleProps {
    position: 'tl' | 'tr' | 'bl' | 'br';
    onResize: (e: React.MouseEvent) => void;
}

const ResizeHandle: React.FC<ResizeHandleProps> = ({ position, onResize }) => {
    const posClass = {
        tl: '-top-2 -left-2 cursor-nwse-resize',
        tr: '-top-2 -right-2 cursor-nesw-resize',
        bl: '-bottom-2 -left-2 cursor-nesw-resize',
        br: '-bottom-2 -right-2 cursor-nwse-resize'
    }[position];

    return (
        <div 
            onMouseDown={onResize}
            className={`absolute w-4 h-4 bg-white border-2 border-indigo-600 rounded-full shadow-md z-50 hover:scale-125 transition-transform ${posClass}`}
        />
    );
};

const InteractiveBlock: React.FC<{
    item: LayoutItem;
    children: React.ReactNode;
    isSelected: boolean;
    onSelect: () => void;
    onUpdateStyle: (id: LayoutSectionId, style: Partial<LayoutItem['style']>) => void;
    onDragStart: (e: React.DragEvent) => void;
    onDragOver: (e: React.DragEvent) => void;
    onDrop: (e: React.DragEvent) => void;
    designMode: boolean;
}> = ({ item, children, isSelected, onSelect, onUpdateStyle, onDragStart, onDragOver, onDrop, designMode }) => {
    const blockRef = useRef<HTMLDivElement>(null);

    const handleResize = (e: React.MouseEvent, corner: string) => {
        e.stopPropagation();
        e.preventDefault();
        const startX = e.clientX;
        const startY = e.clientY;
        const startWidth = blockRef.current?.offsetWidth || 0;
        const startHeight = blockRef.current?.offsetHeight || 0;
        const parentWidth = blockRef.current?.parentElement?.offsetWidth || 1;

        const onMouseMove = (moveEvent: MouseEvent) => {
            const deltaX = moveEvent.clientX - startX;
            const deltaY = moveEvent.clientY - startY;

            let newWidthPx = startWidth;
            let newHeight = startHeight;

            if (corner.includes('r')) newWidthPx = startWidth + deltaX;
            if (corner.includes('l')) newWidthPx = startWidth - deltaX;
            if (corner.includes('b')) newHeight = startHeight + deltaY;
            if (corner.includes('t')) newHeight = startHeight - deltaY;

            const newWidthPercent = Math.min(100, Math.max(20, (newWidthPx / parentWidth) * 100));
            onUpdateStyle(item.id, { 
                widthPercent: Math.round(newWidthPercent), 
                minHeight: Math.max(40, newHeight) 
            });
        };

        const onMouseUp = () => {
            window.removeEventListener('mousemove', onMouseMove);
            window.removeEventListener('mouseup', onMouseUp);
        };

        window.addEventListener('mousemove', onMouseMove);
        window.addEventListener('mouseup', onMouseUp);
    };

    return (
        <div 
            ref={blockRef}
            onClick={(e) => { if(designMode) { e.stopPropagation(); onSelect(); } }}
            draggable={designMode}
            onDragStart={onDragStart}
            onDragOver={onDragOver}
            onDrop={onDrop}
            className={`relative flex flex-col transition-all duration-150 group/block mb-2 ${designMode ? 'cursor-move' : ''} ${isSelected && designMode ? 'ring-2 ring-indigo-500 bg-indigo-50/10' : 'hover:ring-1 hover:ring-indigo-300'}`}
            style={{ 
                width: `${item.style.widthPercent}%`,
                minHeight: `${item.style.minHeight}px`,
                padding: `${item.style.padding}px`,
                marginTop: `${item.style.marginTop}px`,
                marginBottom: `${item.style.marginBottom}px`,
                alignSelf: item.style.alignSelf,
                border: designMode ? '1px dashed #cbd5e1' : 'none',
            }}
        >
            {children}

            {designMode && isSelected && (
                <>
                    <ResizeHandle position="tl" onResize={(e) => handleResize(e, 'tl')} />
                    <ResizeHandle position="tr" onResize={(e) => handleResize(e, 'tr')} />
                    <ResizeHandle position="bl" onResize={(e) => handleResize(e, 'bl')} />
                    <ResizeHandle position="br" onResize={(e) => handleResize(e, 'br')} />

                    <div className="absolute -top-8 left-0 flex gap-1 bg-indigo-600 text-white p-1 rounded-t-lg shadow-lg z-50">
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStyle(item.id, { alignSelf: 'flex-start' }); }} className="p-1 hover:bg-white/20 rounded"><i className="fa-solid fa-align-left"></i></button>
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStyle(item.id, { alignSelf: 'center' }); }} className="p-1 hover:bg-white/20 rounded"><i className="fa-solid fa-align-center"></i></button>
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStyle(item.id, { alignSelf: 'flex-end' }); }} className="p-1 hover:bg-white/20 rounded"><i className="fa-solid fa-align-right"></i></button>
                    </div>
                </>
            )}
        </div>
    );
};

