        const prevDesignMode = designMode;
        setDesignMode(false);
        setTimeout(async () => {
            try {
                await printService.generatePdf('.reading-studio-print-container', storyData.title, { action });
            } finally {
                setDesignMode(prevDesignMode);
            }
        }, 100);
    };

    const updateBlockStyle = useCallback((id: LayoutSectionId, newStyle: Partial<LayoutItem['style']>) => {
        setLayout(prev => prev.map(item => item.id === id ? { ...item, style: { ...item.style, ...newStyle } } : item));
    }, []);

    const onDragStart = (index: number) => (e: React.DragEvent) => {
        draggedItem.current = index;
        e.dataTransfer.effectAllowed = 'move';
    };

    const onDragOver = (e: React.DragEvent) => e.preventDefault();

    const onDrop = (index: number) => (e: React.DragEvent) => {
        e.preventDefault();
        if (draggedItem.current === null) return;
        const newLayout = [...layout];
        const item = newLayout.splice(draggedItem.current, 1)[0];
        newLayout.splice(index, 0, item);
        setLayout(newLayout);
        draggedItem.current = null;
    };

    const renderContent = (id: LayoutSectionId) => {
        if (!storyData) return <div className="p-4 border border-dashed text-zinc-300 italic text-center">İçerik Yükleniyor...</div>;

        switch(id) {
            case 'header': return (
                <div className="border-b-4 border-black pb-2">
                    <EditableText tag="h1" className="text-3xl font-black uppercase leading-tight" value={storyData.title} />
                    <div className="flex justify-between items-end mt-1">
                        <p className="text-sm font-bold text-zinc-500 uppercase">{config.genre} • {config.gradeLevel}</p>
                        <div className="text-[10px] font-bold text-zinc-400 border-b border-black w-24 text-right">Tarih</div>
                    </div>
                </div>
            );
            case 'story_block': return (
                <div className={`relative flex gap-6 h-full ${config.imagePosition === 'right' ? 'flex-row-reverse' : config.imagePosition === 'top' ? 'flex-col' : 'flex-row'}`}>
                    {config.includeImage && (
                        <div 
                            className="shrink-0 border-2 border-black rounded-xl overflow-hidden bg-zinc-50 transition-all"
                            style={{ width: config.imagePosition === 'top' ? '100%' : `${config.imageSize}%`, aspectRatio: '1/1' }}
                        >
                            <ImageDisplay prompt={storyData.imagePrompt} description={storyData.title} className="w-full h-full object-cover grayscale" />
                        </div>
                    )}
                    <div className={`flex-1 text-justify font-serif leading-relaxed ${config.layoutDensity === 'compact' ? 'text-sm' : 'text-lg'}`}>
                        <StoryHighlighter text={storyData.story} highlights={(storyData.fiveW1H || []).map(q => ({ text: q.answer, type: q.type }))} />
                    </div>
                </div>
            );
            case 'vocabulary': return storyData.vocabulary.length > 0 && (
                <div className="p-4 border-2 border-black bg-zinc-50 rounded-xl">
                    <h4 className="font-black text-[10px] uppercase text-zinc-400 mb-2 border-b">SÖZCÜK HAVUZU</h4>
                    <div className="grid grid-cols-2 gap-x-6 gap-y-1">
                         {storyData.vocabulary.map((v, i) => <div key={i} className="text-xs truncate"><span className="font-bold">{v.word}:</span> {v.definition}</div>)}
                    </div>
                </div>
            );
            case 'questions_5n1k': return (
                <div className="mt-4">
                    <h4 className="font-black border-b-2 border-black mb-4 text-sm">METNİ ANLAMA (5N1K)</h4>
                    <div className="space-y-4">
                        {storyData.fiveW1H.map((q, i) => (
                            <div key={i} className="text-sm">
                                <div className="flex gap-2 mb-1">
                                    <span className="shrink-0 px-2 py-0.5 rounded text-[10px] font-black text-white" style={{ backgroundColor: QUESTION_TYPES[q.type]?.color }}>{QUESTION_TYPES[q.type]?.label}</span>
                                    <p className="font-bold truncate">{q.question}</p>
                                </div>
                                <div className="border-b border-dashed border-zinc-400 h-6"></div>
                            </div>
                        ))}
                    </div>
                </div>
            );
            case 'questions_test': return (
                <div className="grid grid-cols-2 gap-8 mt-4">
                    <div>
                        <h4 className="font-black border-b-2 border-black mb-3 text-xs">DOĞRU / YANLIŞ</h4>
                        {storyData.trueFalse?.map((q, i) => (
                            <div key={i} className="text-[11px] mb-2 flex justify-between gap-2">
                                <span className="truncate">{q.question}</span>
                                <span className="font-bold text-zinc-400 whitespace-nowrap">(D) (Y)</span>
                            </div>
                        ))}
                    </div>
                    <div>
                        <h4 className="font-black border-b-2 border-black mb-3 text-xs">TEST SORULARI</h4>
                        {storyData.multipleChoice?.map((q, i) => (
                            <div key={i} className="text-[11px] mb-3">
                                <p className="font-bold mb-1 truncate">{i+1}. {q.question}</p>
                                <div className="flex flex-wrap gap-2">
                                    {q.options.slice(0, 3).map((o, k) => <span key={k} className="before:content-['○'] before:mr-1 truncate max-w-[80px]">{o}</span>)}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            );
            case 'questions_inference': return storyData.inferenceQuestions.length > 0 && (
                <div className="mt-4">
                    <h4 className="font-black border-b-2 border-black mb-4 text-sm flex items-center gap-2"><i className="fa-solid fa-brain text-indigo-500"></i> DERİN DÜŞÜNÜYORUM</h4>
                    {storyData.inferenceQuestions.map((q, i) => (
                        <div key={i} className="text-sm mb-4">
                            <p className="font-bold mb-2">Q: {q.question}</p>
                            <div className="border-b border-dashed border-zinc-400 h-10"></div>
                        </div>
                    ))}
                </div>
            );
            case 'tracker': return (
                <div className="flex items-center gap-4 bg-zinc-50 border border-zinc-200 rounded-lg px-4 h-full">
                    <span className="text-[10px] font-black uppercase text-zinc-400">Okuma Sayısı:</span>
                    {[1,2,3].map(i => <div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-300 bg-white"></div>)}
                </div>
            );
            case 'creative': return (
                <div className="border-2 border-dashed border-indigo-200 bg-indigo-50/20 rounded-2xl p-4 flex flex-col items-center justify-center text-center h-full">
                    <i className="fa-solid fa-pencil text-indigo-200 text-3xl mb-2"></i>
                    <p className="text-xs font-bold text-indigo-900 italic">"{storyData.creativeTask}"</p>
                </div>
            );
            default: return null;
        }
    };

    return (
        <div className="h-full flex flex-col bg-zinc-100 dark:bg-zinc-950 overflow-hidden">
            <div className="h-full flex">

                {/* SETTINGS PANEL (LEFT) */}
                <div className="w-80 h-full bg-white dark:bg-zinc-900 border-r p-6 overflow-y-auto custom-scrollbar shadow-xl shrink-0 z-20">
                    <button onClick={onBack} className="mb-8 text-zinc-400 hover:text-zinc-800 transition-colors text-sm font-bold uppercase flex items-center gap-2">
                        <i className="fa-solid fa-arrow-left"></i> Çıkış
                    </button>

                    <h2 className="text-xl font-black mb-6 flex items-center gap-2">Studio Ayarları</h2>

                    <div className="space-y-6">
                        <div>
                            <label className="block text-[10px] font-black text-zinc-400 uppercase mb-2">Hikaye Konusu</label>
                            <input 
                                type="text" placeholder="Örn: Uzayda Bir Macera"
                                value={config.topic} onChange={e => setConfig({...config, topic: e.target.value})}
                                className="w-full p-3 bg-zinc-50 border rounded-xl font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                             <select value={config.genre} onChange={e => setConfig({...config, genre: e.target.value})} className="w-full p-2 bg-zinc-50 border rounded-lg text-xs font-bold">
                                <option>Macera</option><option>Masal</option><option>Bilim Kurgu</option><option>Fabl</option>
                             </select>
                             <select value={config.gradeLevel} onChange={e => setConfig({...config, gradeLevel: e.target.value})} className="w-full p-2 bg-zinc-50 border rounded-lg text-xs font-bold">
                                <option>1. Sınıf</option><option>2. Sınıf</option><option>3. Sınıf</option><option>4. Sınıf</option>
                             </select>
                        </div>

                        <div className="pt-4 border-t">
                            <label className="flex items-center justify-between mb-4">
                                <span className="text-xs font-bold">Görsel Eklensin mi?</span>
                                <input type="checkbox" checked={config.includeImage} onChange={e => setConfig({...config, includeImage: e.target.checked})} className="w-4 h-4 accent-indigo-600" />
                            </label>
                            {config.includeImage && (
                                <div className="space-y-4 animate-in slide-in-from-top-2">
                                    <div className="grid grid-cols-3 gap-1">
                                        {(['left', 'right', 'top'] as const).map(p => (
                                            <button key={p} onClick={() => setConfig({...config, imagePosition: p})} className={`p-2 text-[8px] font-black uppercase rounded border ${config.imagePosition === p ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-zinc-500'}`}>{p}</button>
                                        ))}
                                    </div>
                                    <input type="range" min="20" max="60" value={config.imageSize} onChange={e => setConfig({...config, imageSize: Number(e.target.value)})} className="w-full h-1 bg-zinc-200 rounded-lg appearance-none accent-indigo-600" />
                                </div>
                            )}
                        </div>

                        <div className="pt-4 border-t space-y-3">
                             <p className="text-[10px] font-black text-zinc-400 uppercase">Soru Adetleri</p>
                             <div className="grid grid-cols-2 gap-3">
                                 <div className="p-2 bg-zinc-50 rounded-lg border text-center">
                                     <span className="text-[10px] block mb-1">TEST</span>
                                     <input type="number" value={config.countMultipleChoice} onChange={e => setConfig({...config, countMultipleChoice: Number(e.target.value)})} className="w-full bg-transparent text-center font-bold" />
                                 </div>
                                 <div className="p-2 bg-zinc-50 rounded-lg border text-center">
                                     <span className="text-[10px] block mb-1">MANTIK</span>
                                     <input type="number" value={config.countLogic} onChange={e => setConfig({...config, countLogic: Number(e.target.value)})} className="w-full bg-transparent text-center font-bold" />
                                 </div>
                             </div>
                        </div>

                        <button 
                            onClick={handleGenerate} disabled={isLoading}
                            className="w-full py-4 bg-zinc-900 hover:bg-black text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-3"
                        >
                            {isLoading ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
                            SİHİRLİ ÜRETİM
                        </button>
                    </div>
                </div>

                {/* ARCHITECT CANVAS (CENTER) */}
                <div className="flex-1 flex flex-col relative" onClick={() => setSelectedBlockId(null)}>
                    {/* Floating Controls */}
                    <div className="absolute top-4 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-white dark:bg-zinc-800 p-2 rounded-2xl shadow-2xl z-50 border border-zinc-200 dark:border-zinc-700 animate-in slide-in-from-top-4">
                        <button onClick={() => setDesignMode(!designMode)} className={`px-4 py-2 rounded-xl text-xs font-black transition-all flex items-center gap-2 ${designMode ? 'bg-indigo-600 text-white' : 'bg-zinc-100 text-zinc-500'}`}>
                            <i className={`fa-solid ${designMode ? 'fa-pen-ruler' : 'fa-eye'}`}></i>
                            {designMode ? 'MİMARİ MOD' : 'ÖNİZLEME MODU'}
                        </button>
                        <div className="h-6 w-px bg-zinc-200"></div>
                        <button onClick={() => handlePrint('print')} className="px-4 py-2 bg-zinc-800 text-white rounded-xl text-xs font-black hover:bg-black active:scale-95 transition-all"><i className="fa-solid fa-print mr-2"></i> YAZDIR</button>
                    </div>

                    <div className="flex-1 overflow-auto p-12 flex justify-center custom-scrollbar bg-zinc-200/50 dark:bg-black/50">
                        <div className="reading-studio-print-container bg-white shadow-[0_0_80px_rgba(0,0,0,0.15)] flex flex-col p-[20mm] relative transition-all duration-300" style={{ width: '210mm', minHeight: '297mm', height: 'auto' }}>

                            {!storyData ? (
                                <div className="flex-1 border-4 border-dashed border-zinc-200 rounded-[3rem] flex flex-col items-center justify-center text-zinc-300 grayscale opacity-50">
                                    <i className="fa-solid fa-file-invoice text-9xl mb-8"></i>
                                    <p className="text-2xl font-black uppercase tracking-widest">İçerik Oluşturun</p>
                                </div>
                            ) : (
                                <div className="flex flex-col h-full">
                                    {layout.map((item, index) => (
                                        item.isVisible && (
                                            <InteractiveBlock
                                                key={item.id}
                                                item={item}
                                                designMode={designMode}
                                                isSelected={selectedBlockId === item.id}
                                                onSelect={() => setSelectedBlockId(item.id)}
                                                onUpdateStyle={updateBlockStyle}
                                                onDragStart={onDragStart(index)}
                                                onDragOver={onDragOver}
                                                onDrop={onDrop(index)}
                                            >
                                                {renderContent(item.id)}
                                            </InteractiveBlock>
                                        )
                                    ))}

                                    <div className="mt-auto pt-8 border-t-2 border-zinc-100 flex justify-between items-end">
                                         <div className="flex flex-col gap-1">
                                             <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">BURSA DİSLEKSİ AI</span>
                                             <span className="text-[8px] font-bold text-zinc-300">PROFESYONEL ÖĞRENME MATERYALİ • 2024</span>
                                         </div>
                                         <div className="w-12 h-12 opacity-10"><i className="fa-solid fa-brain text-5xl"></i></div>
                                    </div>
                                </div>
                            )}

                        </div>
                    </div>
                </div>

            </div>
        </div>
    );
};

import { BaseActivityData, VocabularyItem, WordSearchData, MissingPartsData } from './core';

export * from './core';

export interface StoryQuestion {
    type: 'multiple-choice' | 'open-ended' | 'true-false' | 'logic' | 'vocabulary' | 'inference' | 'bloom_analysis' | 'bloom_synthesis';
    question: string;
    options?: string[]; 
    answer?: string;
    isTrue?: boolean;
    difficultyLevel?: 'easy' | 'medium' | 'hard';
    sentence?: string; // For fill in blank
}

export interface VocabularyItem {
    word: string;
    definition: string;
}

export interface StoryData extends BaseActivityData {
    story: string;
    mainIdea: string;
    characters: string[];
    setting: string;
    vocabulary: VocabularyItem[];
    creativeTask: string;
    questions: StoryQuestion[];
}

export interface StoryAnalysisData extends BaseActivityData {
    story: string;
    storyMap: {
        characters: string;
        setting: string;
        problem: string;
        solution: string;
        theme: string;
    };
}

export interface StoryCreationPromptData extends BaseActivityData {
    prompt: string;
    keywords: string[];
    structureHints: {
        who: string;
        where: string;
        when: string;
        problem: string;
    };
}

export interface WordsInStoryData extends BaseActivityData {
    story: string;
    vocabWork: {
        word: string;
        contextQuestion: string;
        type: 'meaning' | 'usage';
    }[];
}

export interface StorySequencingData extends BaseActivityData {
    prompt: string;
    panels: {
        id: string;
        description: string;
        order: number;
        imagePrompt?: string;
    }[];
    transitionWords?: string[];
}

export interface InteractiveStoryData extends BaseActivityData { 
    story: string; 
    segments: { id: string; text: string; }[]; 
    genre: string;
    gradeLevel: string;
    wordCount: number;

    // Bloom Taxonomy & Intervention Components
    fiveW1H: { question: string; answer: string; type: string }[];
    multipleChoice: { question: string; options: string[]; answer: string }[];
    trueFalse: { question: string; answer: boolean }[];
    fillBlanks: { sentence: string; answer: string }[];
    logicQuestions: { question: string; answer: string; hint: string }[];
    inferenceQuestions: { question: string; answer: string }[]; 
    interventionQuestions: { question: string; type: 'word_hunt' | 'spelling' | 'visual_memory' }[];

    vocabulary: VocabularyItem[]; 
    creativeTask: string; 
    mainIdea: string;
    imagePrompt: string;
    answers?: any[];
}

// Proverb Specific Aliases/Interfaces
export interface ProverbFillData extends MissingPartsData {}
export interface ProverbSayingSortData extends StoryData {}
export interface ProverbWordChainData extends StorySequencingData {}
export interface ProverbSentenceFinderData extends StorySequencingData {}
export interface ProverbSearchData extends WordSearchData {}

export interface ReadingStudioConfig {
    gradeLevel: string;
    studentName: string;
    topic: string;
    genre: string;
    tone: string;
    length: 'short' | 'medium' | 'long';
    layoutDensity: 'comfortable' | 'compact';

    // Image Advanced Controls
    includeImage: boolean;
    imageSize: number; // Percentage 10-100
    imagePosition: 'top' | 'left' | 'right' | 'center' | 'background';
    imageOpacity: number; // For background mode

    // Bloom Taxonomy Structure
    include5N1K: boolean;
    countMultipleChoice: number;
    countTrueFalse: number;
    countFillBlanks: number;
    countLogic: number; // Evaluation level
    countInference: number; // Analysis/Inference level

    // Intervention Modules
    includeWordHunt: boolean;
    includeSpellingCheck: boolean;
    focusVocabulary: boolean;
    includeCreativeTask: boolean;

    // UI Modules
    showReadingTracker: boolean;
    showSelfAssessment: boolean;
    showTeacherNotes: boolean;
    showDateSection: boolean;
}

export type LayoutSectionId = 'header' | 'tracker' | 'story_block' | 'vocabulary' | 'questions_5n1k' | 'questions_test' | 'questions_inference' | 'creative' | 'self_eval' | 'notes';

export interface LayoutItemStyle {
    widthPercent: number; // 20 - 100
    minHeight: number; // px
    padding: number; // px
    marginTop: number; // px
    marginBottom: number; // px
    alignSelf: 'flex-start' | 'center' | 'flex-end';
    backgroundColor?: string;
    borderWidth?: number;
}

export interface LayoutItem {
    id: LayoutSectionId;
    label: string;
    icon: string;
    isVisible: boolean;
    style: LayoutItemStyle;
}

